+export interface DurationObservation {
+  duration: number
+  recordedAt: number
+}
+
+export function smoothDuration(observations: DurationObservation[], mode: 'latest' | 'average' | 'p95' | 'median'): number {
+  if (!observations.length) return 0
+  if (mode === 'latest') return observations.reduce((latest, item) => item.recordedAt > latest.recordedAt ? item : latest).duration
+  const values = observations.map(item => item.duration).sort((a, b) => a - b)
+  if (mode === 'average') return Math.round(values.reduce((sum, value) => sum + value, 0) / values.length)
+  if (mode === 'p95') return values[Math.ceil(.95 * values.length) - 1]
+  const middle = Math.floor(values.length / 2)
+  return values.length % 2 ? values[middle] : Math.floor((values[middle - 1] + values[middle]) / 2)
