+export type DurationHistory = Record<string, { observations: DurationObservation[] }>
+
+export async function readDurationHistory(path: string, ttl: number): Promise<DurationHistory | null> {
+  try {
+    const raw = JSON.parse(await readFile(path, 'utf8'))
+    if (!raw || typeof raw !== 'object' || Array.isArray(raw)) return null
+    const cutoff = Date.now() - ttl
+    const history: DurationHistory = {}
+    for (const [file, value] of Object.entries(raw)) {
+      const observations = typeof value === 'number' ? [{ duration: value, recordedAt: 0 }] : Array.isArray((value as any)?.observations) ? (value as any).observations : (value as any)?.duration != null ? [value] : null
+      if (!observations || observations.some((item: any) => !Number.isFinite(item.duration) || !Number.isFinite(item.recordedAt))) return null
+      history[file] = { observations: observations.filter((item: DurationObservation) => !ttl || item.recordedAt === 0 || item.recordedAt >= cutoff) }
+    }
+    return history
+  }
+  catch { return null }
