+export async function writeDurationHistory(root: string, relativePath: string, ttl: number, maxRuns: number, durations: Record<string, number>): Promise<void> {
+  const path = resolve(root, relativePath)
+  const history = await readDurationHistory(path, ttl) || {}
+  const now = Date.now()
